sql:
SELECT location, capacity
FROM landfill_sites
WHERE mga_b_status = 'Active' AND capacity > 400000;

SELECT plan_status, COUNT(*) AS number_of_plans
FROM development_plans
GROUP BY plan_status;

SELECT mga_b_status, COUNT(*) AS total_sites
FROM landfill_sites
GROUP BY mga_b_status;

SELECT geodb_oid, shape_area
FROM landfill_sites
ORDER BY shape_area DESC;

SELECT report_summary, compliance_status
FROM environmental_reports
WHERE compliance_status = 'Non-Compliant';

external_knowledge:
- Non-compliant reports refer to environmental reports that do not meet the required environmental regulations; 
- Follow-up actions are required when a report indicates the need for further investigation or action; 
- The last 3 months refer to the time period from the current date going back 3 months.

; 
; Active development plans refer to plans with a status of 'Active'.
; Recent inspections refer to the most recent inspection of each landfill site.

